package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.BeforeEach;
import org.mockito.Mockito;

import java.lang.reflect.Field;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        // Create a CSVFormat instance with default constructor via reflection or use DEFAULT and modify
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testIsCommentMarkerSet_whenCommentMarkerIsNull() throws Exception {
        // Use reflection to set private field commentMarker to null
        Field commentMarkerField = CSVFormat.class.getDeclaredField("commentMarker");
        commentMarkerField.setAccessible(true);
        commentMarkerField.set(csvFormat, null);

        assertFalse(csvFormat.isCommentMarkerSet());
    }

    @Test
    void testIsCommentMarkerSet_whenCommentMarkerIsSet() throws Exception {
        // Use reflection to set private field commentMarker to a non-null Character
        Field commentMarkerField = CSVFormat.class.getDeclaredField("commentMarker");
        commentMarkerField.setAccessible(true);
        commentMarkerField.set(csvFormat, '#');

        assertTrue(csvFormat.isCommentMarkerSet());
    }

    @Test
    void testIsCommentMarkerSet_onNewInstanceWithCommentMarker() {
        CSVFormat formatWithComment = csvFormat.withCommentMarker('#');
        assertTrue(formatWithComment.isCommentMarkerSet());
    }

    @Test
    void testIsCommentMarkerSet_onNewInstanceWithoutCommentMarker() {
        CSVFormat formatWithoutComment = csvFormat.withCommentMarker((Character) null);
        assertFalse(formatWithoutComment.isCommentMarkerSet());
    }
}
